class Solution:
    def wiggleMaxLength(self, nums):
        n = len(nums)
        if n == 0:
            return 0
        from functools import lru_cache
        best = 1
        # dp[i][d]: longest wiggle ending at i with last step direction d (1 up, -1 down, 0 none)
        up = [1] * n
        down = [1] * n
        for i in range(n):
            for j in range(i):
                if nums[i] > nums[j]:
                    up[i] = max(up[i], down[j] + 1)
                elif nums[i] < nums[j]:
                    down[i] = max(down[i], up[j] + 1)
            best = max(best, up[i], down[i])
        return best

